486	    @RequestMapping(value = "/sign")
487	    @ResponseBody
488	    public Object sign(HttpServletRequest request) {
489	        long wmPoiId = GetParameterUtil.getWmPoiId(request);
490	        long activityId = GetParameterUtil.getLongParam(request, "activityId");
491	        String cashRatio = GetParameterUtil.getStrParam(request, "cashRatio");
492	        try {
493	            SdfSignExtraInfoDTO extraInfoDTO = new SdfSignExtraInfoDTO();
494	            extraInfoDTO.setAcctId(GetParameterUtil.getLongParam(request, Constants.ACCT_ID));
495	            extraInfoDTO.setIp(GetParameterUtil.getRealIp(request));
496	            extraInfoDTO.setPlatform(GetParameterUtil.getIntParam(request, Constants.PLAT_FORM));
497	            extraInfoDTO.setToken(GetParameterUtil.getStrParam(request, Constants.TOKEN));
498	
499	            Result result = wmAdBillingMoneyProxy.sdfSignWithRatio(wmPoiId, PartnerType.POI.getIntValue(), activityId, 1002, extraInfoDTO, cashRatio);
500	            return MiscUtils.getReturnMessage(result.isSuccess() ? 0 : 1,
501	                    result.isSuccess() ? "OK" : result.getMessage(), null);
502	        } catch (Exception e) {
503	            log.error("AdPoiSdfController sign partnerId orderback sign error,partnerId:{} activityId:{}", wmPoiId, activityId, e);
504	            return MiscUtils.getReturnMessage(CODE_ERROR, ERROR, "系统出问题啦，请联系管理员");
505	        }
506	    }
